-- ---- Lookups + future-phase tables: fail-closed ----
-- RLS enabled with no policies so only service_role can read/write until the
-- relevant phase opens them up explicitly.

ALTER TABLE "world_map_nodes"      ENABLE ROW LEVEL SECURITY;
ALTER TABLE "world_map_nodes"      FORCE ROW LEVEL SECURITY;
CREATE POLICY "world_map_nodes_select_authenticated"
  ON "world_map_nodes" FOR SELECT TO authenticated
  USING (true);

ALTER TABLE "practice_games"       ENABLE ROW LEVEL SECURITY;
ALTER TABLE "practice_games"       FORCE ROW LEVEL SECURITY;
-- Practice games are gated by their parent topic.is_published — published-topic
-- policy at the topics level + service-role seeding keeps this safe in Phase 2.
CREATE POLICY "practice_games_select_via_published_topic"
  ON "practice_games" FOR SELECT TO authenticated
  USING (
    EXISTS (SELECT 1 FROM public.topics t WHERE t.id = "practice_games".topic_id AND t.is_published = true)
  );

