ALTER TABLE "daily_challenges"     FORCE ROW LEVEL SECURITY;
-- Daily challenges cache question IDs that are themselves filtered by RLS on
-- quiz_questions; allow authenticated reads of the cache.
CREATE POLICY "daily_challenges_select_authenticated"
  ON "daily_challenges" FOR SELECT TO authenticated
  USING (true);

